// ─── Shared photo component ───────────────────────────────────────────────────
function Photo({ src, style={} }) {
return <img src={src} alt="" style={{ width:"100%", height:"100%", objectFit:"cover", display:"block", ...style }} />;
}

// ─── Scissors coupon divider ──────────────────────────────────────────────────
function ScissorLine({ color="rgba(255,212,158,0.5)" }) {
return (
<div style={{ display:"flex", alignItems:"center", gap:3, width:"100%" }}>
<span style={{ fontSize:9, opacity:0.7 }}>✂</span>
<div style={{ flex:1, borderTop:`1.5px dashed ${color}` }} />
</div>
);
}

